using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class ReportingFunction
{
    [FunctionName("QueryReportingData")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            if (string.IsNullOrEmpty(connectionString))
            {
                return new BadRequestObjectResult("Connection string not configured");
            }

            var parameters = new Dictionary<string, object>();
            var filterConditions = new List<string>();
            var orderByClause = string.Empty;
            var limitClause = string.Empty;

            foreach (var param in req.Query)
            {
                if (string.IsNullOrEmpty(param.Value.ToString()))
                    continue;

                var paramName = param.Key.ToLower();
                var paramValue = param.Value.ToString();

                switch (paramName)
                {
                    case "orderby":
                        orderByClause = $" ORDER BY {SanitizeIdentifier(paramValue)}";
                        break;
                    case "limit":
                        if (int.TryParse(paramValue, out int limit))
                        {
                            limitClause = $" TOP {Math.Min(limit, 10000)}";
                        }
                        break;
                    default:
                        if (IsValidIdentifier(paramName))
                        {
                            filterConditions.Add($"[{paramName}] = @param_{paramName}");
                            parameters[$"@param_{paramName}"] = paramValue;
                        }
                        break;
                }
            }

            var sqlQuery = $"SELECT {limitClause} * FROM ReportingTable WHERE 1=1";

            if (filterConditions.Any())
            {
                sqlQuery += " AND " + string.Join(" AND ", filterConditions);
            }

            sqlQuery += orderByClause;

            using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            using var command = new SqlCommand(sqlQuery, connection);
            
            foreach (var param in parameters)
            {
                command.Parameters.AddWithValue(param.Key, param.Value ?? DBNull.Value);
            }

            using var reader = await command.ExecuteReaderAsync();
            var results = new List<Dictionary<string, object>>();

            while (await reader.ReadAsync())
            {
                var row = new Dictionary<string, object>();
                for (int i = 0; i < reader.FieldCount; i++)
                {
                    row[reader.GetName(i)] = reader.GetValue(i) ?? DBNull.Value;
                }
                results.Add(row);
            }

            return new OkObjectResult(results);
        }
        catch (Exception ex)
        {
            log.LogError($"Error in QueryReportingData: {ex.Message}");
            return new StatusCodeResult(500);
        }
    }

    private static bool IsValidIdentifier(string identifier)
    {
        if (string.IsNullOrEmpty(identifier))
            return false;

        return identifier.All(c => char.IsLetterOrDigit(c) || c == '_');
    }

    private static string SanitizeIdentifier(string identifier)
    {
        if (string.IsNullOrEmpty(identifier))
            return string.Empty;

        var sanitized = new string(identifier.Where(c => char.IsLetterOrDigit(c) || c == '_').ToArray());
        return sanitized.Length > 0 ? sanitized : "id";
    }
}